import { getProjectBySlug, getProjects, getNextProject } from "@/data/projects"
import { FadeIn } from "@/components/animations/FadeIn"
import Image from "next/image"
import { Link } from "@/i18n/routing"
import { notFound } from "next/navigation"
import { getTranslations, setRequestLocale } from "next-intl/server"
import { CaseGallery } from "@/components/page-specific/CaseGallery"
import { BreadcrumbJsonLd } from "@/components/seo/BreadcrumbJsonLd"
import { CTA } from "@/components/sections/CTA"

export async function generateStaticParams() {
    const projects = await getProjects()
    return projects.map((p) => ({ slug: p.slug }))
}

export async function generateMetadata({ params }: { params: Promise<{ locale: string, slug: string }> }) {
    const { slug, locale } = await params;
    const project = getProjectBySlug(slug);

    if (!project) return { title: 'Case Not Found | Palaz' };

    try {
        const tMetadata = await getTranslations({ locale, namespace: "Metadata" });
        const tData = await getTranslations({ locale, namespace: "ProjectsData" });

        const translatedTitle = tData.has(`${slug}.title`) ? tData(`${slug}.title`) : project.title;
        const translatedDesc = tData.has(`${slug}.description`) ? tData(`${slug}.description`) : (project.description || "");
        const translatedCategory = tData.has(`${slug}.category`) ? tData(`${slug}.category`) : (project.category || "");

        // Automatic SEO logic: 
        // 1. Try to get keywords from i18n (optional override)
        // 2. Fallback to Project Title + Category
        let projectKeywords = '';
        if (tData.has(`${slug}.keywords`)) {
            projectKeywords = tData(`${slug}.keywords`);
        }

        // If not provided in i18n, generate automatically
        if (!projectKeywords || projectKeywords === `ProjectsData.${slug}.keywords`) {
            projectKeywords = `${translatedTitle}${translatedCategory ? `, ${translatedCategory}` : ''}`;
        }

        const caseKeywords = projectKeywords ? `, ${projectKeywords}` : '';
        const globalKeywords = tMetadata('keywords');

        return {
            title: `${translatedTitle} | Palaz`,
            description: translatedDesc.substring(0, 160),
            keywords: `${globalKeywords}${caseKeywords}`,
            openGraph: {
                title: `${translatedTitle} | Palaz Strategy & Design`,
                description: translatedDesc.substring(0, 160),
                type: 'article',
                url: `https://palaz.com.br/${locale}/cases/${slug}`,
                images: [
                    {
                        url: project.imageSrc,
                        width: 1200,
                        height: 630,
                        alt: translatedTitle,
                    },
                ],
            },
            alternates: {
                canonical: locale === 'pt' ? `/cases/${slug}` : `/${locale}/cases/${slug}`,
                languages: {
                    'pt-BR': `/cases/${slug}`,
                    'en-US': `/en/cases/${slug}`,
                    'x-default': `/cases/${slug}`
                }
            },
            twitter: {
                card: 'summary_large_image',
                title: translatedTitle,
                description: translatedDesc.substring(0, 160),
                images: [project.imageSrc],
            },
        };
    } catch(e) {
         return {
             title: `${project.title || 'Case'} | Palaz`,
             description: (project.description || "").substring(0, 160)
         };
    }
}

export default async function ProjectPage({ params }: { params: Promise<{ slug: string, locale: string }> }) {
    const { slug, locale } = await params
    setRequestLocale(locale);
    const project = getProjectBySlug(slug)
    const tDetails = await getTranslations("ProjectDetails")
    const tData = await getTranslations("ProjectsData")

    if (!project) {
        notFound()
    }

    return (
        <>
            <BreadcrumbJsonLd 
                items={[
                    { name: 'Palaz', item: 'https://palaz.com.br' },
                    { name: 'Cases', item: 'https://palaz.com.br/cases' },
                    { name: tData.has(`${slug}.title`) ? tData(`${slug}.title`) : project.title, item: `https://palaz.com.br/${locale}/cases/${slug}` }
                ]}
            />
            <div className="w-full min-h-screen bg-black">
                {/* Hero image */}
                <div className="relative w-full h-[70vh] overflow-hidden">
                    <div className="absolute inset-0 z-0 overflow-hidden">
                        <FadeIn direction="none" scale={1.1} duration={1.2} className="absolute inset-0 h-full w-full">
                            <Image
                                src={project.imageSrc}
                                alt={tData(`${slug}.title`) || project.title}
                                fill
                                className="object-cover"
                                priority
                                sizes="100vw"
                                quality={90}
                            />
                        </FadeIn>
                    </div>
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent z-10 pointer-events-none" />
                </div>

                {/* Project Info */}
                <div className="max-w-[1440px] mx-auto px-6 md:px-10 lg:px-[60px] py-16 md:py-20 relative z-20">
                    <div className="grid grid-cols-1 xl:grid-cols-12 gap-12 xl:gap-16">
                        {/* Left: Title + Description */}
                        <div className="xl:col-span-7 order-2 xl:order-1">
                            <FadeIn scale={0.98}>

                                  <h1 className="text-5xl md:text-6xl xl:text-7xl font-medium tracking-[-0.04em] text-white mb-6 md:mb-8">
                                    {tData.has(`${slug}.title`) ? tData(`${slug}.title`) : project.title}
                                 </h1>

                                 <p className="text-white/60 text-base md:text-lg leading-relaxed mb-8 whitespace-pre-line max-w-3xl">
                                    {tData.has(`${slug}.description`) ? tData(`${slug}.description`) : project.description}
                                 </p>
                            </FadeIn>

                        </div>

                        {/* Right: Sidebar info */}
                        <div className="xl:col-span-5 order-1 xl:order-2">
                            <FadeIn scale={0.98} delay={0.2}>
                                <div className="bg-white/[0.03] border border-white/10 rounded-2xl p-6 md:p-8">
                                    {[
                                        { label: tDetails("client"), value: (tData.has(`${slug}.client`) ? tData(`${slug}.client`) : project.client) },
                                        { label: tDetails("year"), value: project.year },
                                        { label: tDetails("category"), value: (tData.has(`${slug}.category`) ? tData(`${slug}.category`) : project.category) },
                                        { label: tDetails("role"), value: (tData.has(`${slug}.role`) ? tData(`${slug}.role`) : project.role) },
                                    ].map((item) => (
                                        <div key={item.label} className="flex justify-between items-start py-4 border-b border-white/5 last:border-b-0">
                                            <span className="text-white/40 text-sm uppercase tracking-widest pt-1">{item.label}</span>
                                            <span className="text-white text-sm font-medium whitespace-pre-line text-right">{item.value}</span>
                                        </div>
                                    ))}
                                </div>
                            </FadeIn>
                        </div>
                    </div>
                </div>

                <CaseGallery 
                    project={project} 
                    slug={slug} 
                />

                {/* CTA Section */}
                <CTA />

                {/* Navigation and Back link */}
                <div className="max-w-[1440px] mx-auto px-6 md:px-10 lg:px-[60px] pb-16 md:pb-20">
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10 md:gap-12 border-t border-white/10 pt-10 md:pt-12">
                        <FadeIn delay={0.2}>
                            <Link href="/cases" className="inline-flex items-center gap-2 text-white/40 text-sm uppercase tracking-widest font-semibold hover:text-white transition-colors">
                                ÔåÉ {tDetails("back_button")}
                            </Link>
                        </FadeIn>

                        {(() => {
                            const nextProject = getNextProject(slug);
                            return (
                                <FadeIn delay={0.3}>
                                    <Link href={`/cases/${nextProject.slug}`} className="group flex flex-col items-end text-right">
                                        <span className="text-white/40 text-[10px] uppercase tracking-[0.2em] mb-2">{tDetails("next_project") || "Pr├│ximo Projeto"}</span>
                                        <span className="text-2xl md:text-3xl lg:text-4xl text-white font-medium group-hover:text-[#F24B0F] transition-colors">
                                            {tData.has(`${nextProject.slug}.title`) ? tData(`${nextProject.slug}.title`) : nextProject.title} ÔåÆ
                                        </span>
                                    </Link>
                                </FadeIn>
                            );
                        })()}
                    </div>
                </div>

            </div>
        </>
    )
}

import { getProjects } from "@/data/projects"
import { ProjectCard } from "@/components/ui/ProjectCard"
import { FadeIn } from "@/components/animations/FadeIn"
import { getTranslations, setRequestLocale } from "next-intl/server"
import { CTA } from "@/components/sections/CTA"

export default async function CasesPage({ params }: { params: Promise<{ locale: string }> }) {
    const { locale } = await params;
    setRequestLocale(locale);
    const rawProjects = (await getProjects()).sort((a, b) => {
        const aOrder = (a as any).casesPageOrder ?? 999;
        const bOrder = (b as any).casesPageOrder ?? 999;
        return aOrder - bOrder;
    });
    const t = await getTranslations("Projetos")
    const tData = await getTranslations("ProjectsData")

    const projects = rawProjects.map(p => ({
        ...p,
        title: tData(`${p.slug}.title`),
        client: tData(`${p.slug}.client`),
        category: tData(`${p.slug}.category`),
        role: tData(`${p.slug}.role`),
        description: tData(`${p.slug}.description`),
        year: p.year
    }))

    return (
        <div className="w-full min-h-screen bg-black text-white selection:bg-[#F24B0F] selection:text-white">
            {/* --- HERO SECTION --- */}
            <section className="relative w-full pt-32 lg:pt-48 pb-32 md:pb-40 px-6 md:px-10 lg:px-[60px] overflow-hidden">
                <div className="max-w-[1440px] mx-auto w-full">
                    <FadeIn>
                        <h1 className="text-[clamp(45px,8vw,120px)] font-bold tracking-[-0.04em] leading-[0.9] max-w-6xl mb-16 md:mb-24">
                            Projetos que <br />
                            <span className="font-serif italic text-[#F24B0F]">forjamos</span>
                        </h1>
                    </FadeIn>

                    <div className="grid grid-cols-1 xl:grid-cols-12 gap-10 md:gap-12 xl:gap-20">
                        <div className="xl:col-span-7">
                            <FadeIn delay={0.2}>
                                <p className="text-2xl md:text-3xl xl:text-4xl font-normal tracking-tight leading-[1.2] text-white/90 max-w-3xl">
                                    {t("hero.description_main")}
                                </p>
                            </FadeIn>
                        </div>
                        <div className="xl:col-span-5 xl:border-l xl:border-white/10 xl:pl-12">
                            <FadeIn delay={0.4}>
                                <p className="text-lg text-white/50 leading-relaxed font-light md:max-w-2xl xl:max-w-none">
                                    {t("hero.description")}
                                </p>
                            </FadeIn>
                        </div>
                    </div>
                </div>
            </section>

            {/* --- PROJECTS LISTING --- */}
            <section className="w-full py-16 md:py-24 bg-black border-t border-white/5">
                <div className="w-full px-6 md:px-10 lg:px-[50px]">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                        {projects.map((project, idx) => (
                            <ProjectCard
                                key={project.slug}
                                {...project}
                                index={idx}
                            />
                        ))}
                    </div>
                </div>
            </section>

            {/* --- CTA SECTION --- */}
            <CTA />
        </div>
    )
}

import { NextResponse } from "next/server";
import fs from "fs/promises";
import path from "path";

function checkEnv() {
    if (process.env.NODE_ENV !== "development") {
        throw new Error("Editor API is only available in development mode.");
    }
}

const getFilePath = (relPath: string) => path.join(process.cwd(), relPath);

function slugify(text: string) {
    return text.toString().toLowerCase()
        .replace(/\s+/g, '-')           // Replace spaces with -
        .replace(/[^\w\-]+/g, '')       // Remove all non-word chars
        .replace(/\-\-+/g, '-')         // Replace multiple - with single -
        .replace(/^-+/, '')             // Trim - from start of text
        .replace(/-+$/, '');            // Trim - from end of text
}

async function readJsonFile(relPath: string) {
    const filePath = getFilePath(relPath);
    try {
        const fileContent = await fs.readFile(filePath, "utf-8");
        return JSON.parse(fileContent);
    } catch (e: unknown) {
        const err = e as Error;
        console.error(`Error reading ${relPath}:`, err.message);
        throw err;
    }
}

async function writeJsonFile(relPath: string, data: unknown) {
    const filePath = getFilePath(relPath);
    await fs.writeFile(filePath, JSON.stringify(data, null, 4), "utf-8");
}

export async function GET(req: Request) {
    try {
        checkEnv();
        const url = new URL(req.url);
        const requestSlug = url.searchParams.get("slug");

        const data = await readJsonFile("src/data/projects.json");

        if (requestSlug) {
            const project = data.find((p: Record<string, unknown>) => p.slug === requestSlug);
            if (!project) return NextResponse.json({ error: "Not found" }, { status: 404 });

            let ptTrans = {};
            let enTrans = {};
            try {
                const ptData = await readJsonFile("src/messages/pt.json");
                ptTrans = ptData.ProjectsData?.[requestSlug] || {};
                const enData = await readJsonFile("src/messages/en.json");
                enTrans = enData.ProjectsData?.[requestSlug] || {};
            } catch {
                // Ignore missing translation files silently
            }

            return NextResponse.json({
                projectData: project,
                translations: { pt: ptTrans, en: enTrans }
            });
        }

        // Para a listagem, vamos carregar as categorias do pt.json para exibir no dashboard
        const ptData = await readJsonFile("src/messages/pt.json").catch(() => ({}));
        const projectsWithCategory = data.map((p: Record<string, any>) => ({
            ...p,
            category: ptData.ProjectsData?.[p.slug]?.category || ""
        }));

        return NextResponse.json(projectsWithCategory);
    } catch (e: unknown) {
        const err = e as Error;
        return NextResponse.json({ error: err.message }, { status: 403 });
    }
}

export async function POST(req: Request) {
    try {
        checkEnv();
        const body = await req.json();
        const { projectData, translations } = body;

        const generatedTitle = projectData.title || translations?.pt?.title || translations?.en?.title || "";
        const slug = projectData.slug || slugify(generatedTitle);

        if (!slug) {
            return NextResponse.json({ error: "Slug inv├ílido. O projeto precisa ter um t├¡tulo para ser salvo." }, { status: 400 });
        }

        projectData.slug = slug;

        // 1. Update projects.json
        const projects = await readJsonFile("src/data/projects.json");

        // Check if slug already exists
        if (projects.find((p: Record<string, unknown>) => p.slug === slug)) {
            return NextResponse.json({ error: "Slug already exists. Choose a different title or slug." }, { status: 400 });
        }

        projects.push(projectData);
        await writeJsonFile("src/data/projects.json", projects);

        // 2. Update Translations
        if (translations && translations.pt) {
            const ptData = await readJsonFile("src/messages/pt.json");
            if (!ptData.ProjectsData) ptData.ProjectsData = {};
            ptData.ProjectsData[slug] = translations.pt;
            await writeJsonFile("src/messages/pt.json", ptData);
        }

        if (translations && translations.en) {
            const enData = await readJsonFile("src/messages/en.json");
            if (!enData.ProjectsData) enData.ProjectsData = {};
            enData.ProjectsData[slug] = translations.en;
            await writeJsonFile("src/messages/en.json", enData);
        }

        return NextResponse.json({ success: true, slug, project: projectData });
    } catch (e: unknown) {
        const err = e as Error;
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

export async function PUT(req: Request) {
    try {
        checkEnv();
        const body = await req.json();
        const { projectData, translations, originalSlug } = body;

        const slug = projectData.slug;
        if (!slug || !originalSlug) {
            return NextResponse.json({ error: "Missing slug or originalSlug" }, { status: 400 });
        }

        // 1. Update projects.json
        const projects = await readJsonFile("src/data/projects.json");
        const index = projects.findIndex((p: Record<string, unknown>) => p.slug === originalSlug);

        if (index === -1) {
            return NextResponse.json({ error: "Project not found" }, { status: 404 });
        }

        projects[index] = projectData;
        await writeJsonFile("src/data/projects.json", projects);

        // 2. Update Translations
        const updateLocale = async (locale: string, transData: Record<string, unknown>) => {
            if (!transData) return;
            const fileData = await readJsonFile(`src/messages/${locale}.json`);
            if (!fileData.ProjectsData) fileData.ProjectsData = {};

            // If slug changed, delete old key
            if (slug !== originalSlug) {
                delete fileData.ProjectsData[originalSlug];
            }
            fileData.ProjectsData[slug] = transData;
            await writeJsonFile(`src/messages/${locale}.json`, fileData);
        };

        if (translations?.pt) await updateLocale("pt", translations.pt);
        if (translations?.en) await updateLocale("en", translations.en);

        // If slug changed, we might need to rename the public/imagens/cases folder
        if (slug !== originalSlug) {
            const oldPath = getFilePath(`public/imagens/cases/${originalSlug}`);
            const newPath = getFilePath(`public/imagens/cases/${slug}`);
            try {
                // Check if old folder exists
                const stat = await fs.stat(oldPath).catch(() => null);
                if (stat?.isDirectory()) {
                    await fs.rename(oldPath, newPath);
                }
            } catch (err) {
                console.error("Failed to rename public media folder", err);
            }
        }

        return NextResponse.json({ success: true, slug, project: projectData });
    } catch (e: unknown) {
        const err = e as Error;
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

export async function PATCH(req: Request) {
    try {
        checkEnv();
        const body = await req.json();

        // Suporte legado: array direto = reorder home
        if (Array.isArray(body)) {
            await writeJsonFile("src/data/projects.json", body);
            return NextResponse.json({ success: true });
        }

        const { type, projects: orderedSlugs } = body;

        if (!type || !Array.isArray(orderedSlugs)) {
            return NextResponse.json({ error: "Invalid data format" }, { status: 400 });
        }

        const currentProjects = await readJsonFile("src/data/projects.json");

        if (type === 'home') {
            // Reordena o array principal pela ordem dos slugs recebidos
            const reordered = orderedSlugs
                .map((slug: string) => currentProjects.find((p: any) => p.slug === slug))
                .filter(Boolean);
            // Adiciona projetos que n├úo estavam na lista (seguran├ºa)
            const remaining = currentProjects.filter((p: any) => !orderedSlugs.includes(p.slug));
            await writeJsonFile("src/data/projects.json", [...reordered, ...remaining]);
        } else if (type === 'cases') {
            // Atribui casesPageOrder baseado na posi├º├úo recebida
            const updated = currentProjects.map((p: any) => {
                const idx = orderedSlugs.indexOf(p.slug);
                return { ...p, casesPageOrder: idx >= 0 ? idx : 999 };
            });
            await writeJsonFile("src/data/projects.json", updated);
        }

        return NextResponse.json({ success: true });
    } catch (e: unknown) {
        const err = e as Error;
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

export async function DELETE(req: Request) {
    try {
        checkEnv();
        const url = new URL(req.url);
        const slug = url.searchParams.get("slug");

        if (!slug) {
            return NextResponse.json({ error: "Slug is required for deletion" }, { status: 400 });
        }

        // 1. Apagar do projects.json
        const projects = await readJsonFile("src/data/projects.json");
        const filteredProjects = projects.filter((p: Record<string, unknown>) => p.slug !== slug);

        if (projects.length === filteredProjects.length) {
            return NextResponse.json({ error: "Project not found" }, { status: 404 });
        }

        await writeJsonFile("src/data/projects.json", filteredProjects);

        // 2. Apagar Tradu├º├Áes
        const removeTranslation = async (locale: string) => {
            try {
                const fileData = await readJsonFile(`src/messages/${locale}.json`);
                if (fileData.ProjectsData && fileData.ProjectsData[slug]) {
                    delete fileData.ProjectsData[slug];
                    await writeJsonFile(`src/messages/${locale}.json`, fileData);
                }
            } catch (err) {
                // Ignore silent misses
            }
        };

        await removeTranslation("pt");
        await removeTranslation("en");

        // 3. Deletar pasta de m├¡dia do case
        const folderPath = getFilePath(`public/imagens/cases/${slug}`);
        try {
            await fs.rm(folderPath, { recursive: true, force: true });
        } catch (err) {
            console.error(`Failed to delete folder for project ${slug}`, err);
        }

        return NextResponse.json({ success: true, deletedSlug: slug });
    } catch (e: unknown) {
        const err = e as Error;
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import TranslationPipeline from "@/lib/translator";

// Mapeamento de idiomas para o formato NLLB-200
const langMap: Record<string, string> = {
    pt: 'por_Latn',
    en: 'eng_Latn'
};

async function translateTextLocal(text: string, from: string, to: string) {
    if (!text) return "";

    try {
        const translator = await TranslationPipeline.getInstance();
        if (!translator) return text;

        // Dividir em par├ígrafos para preservar a estrutura exata e evitar resumos/truncamentos
        const paragraphs = text.split('\n');
        const translatedParagraphs = await Promise.all(
            paragraphs.map(async (p) => {
                if (!p.trim()) return p; // Mant├®m linhas em branco
                const output = await (translator as any)(p, {
                    src_lang: langMap[from] || from,
                    tgt_lang: langMap[to] || to,
                });
                return output[0].translation_text;
            })
        );

        return translatedParagraphs.join('\n');
    } catch (e) {
        console.error("Erro na tradu├º├úo local:", e);
        // Fallback para online se o modelo local falhar ou n├úo estiver carregado
        return translateTextOnline(text, from, to);
    }
}

async function translateTextOnline(text: string, from: string, to: string) {
    try {
        const res = await fetch(`https://translate.googleapis.com/translate_a/single?client=gtx&sl=${from}&tl=${to}&dt=t&q=${encodeURIComponent(text)}`);
        const data = await res.json();
        if (data && data[0]) {
            return data[0].map((s: any) => s[0]).join("");
        }
        return text;
    } catch (e) {
        return text;
    }
}

export async function POST(req: Request) {
    try {
        const { text, title, from, to } = await req.json();

        // Tentamos tradu├º├úo local primeiro (offline)
        const translatedText = await translateTextLocal(text, from, to);
        const translatedTitle = await translateTextLocal(title, from, to);

        return NextResponse.json({ 
            success: true, 
            translatedText, 
            translatedTitle 
        });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import fs from "fs/promises";
import path from "path";

export async function POST(req: Request) {
    if (process.env.NODE_ENV !== "development") {
        return NextResponse.json({ error: "Unauthorized. Editor API is only available in development mode." }, { status: 403 });
    }

    try {
        const formData = await req.formData();
        const files = formData.getAll("files") as File[];
        const slug = formData.get("slug") as string | null;

        if (files.length === 0 || !slug) {
            return NextResponse.json({ error: "Missing files or slug." }, { status: 400 });
        }

        const urls: string[] = [];
        const dirPath = path.join(process.cwd(), `public/imagens/cases/${slug}`);
        await fs.mkdir(dirPath, { recursive: true });

        for (const file of files) {
            const buffer = Buffer.from(await file.arrayBuffer());

            // Pega a extens├úo e o nome base separadamente
            const ext = path.extname(file.name).toLowerCase();
            const baseName = path.basename(file.name, ext)
                .replace(/\s+/g, '-')
                .toLowerCase()
                .replace(/[^\w-]/g, ''); // Remove caracteres especiais

            // Gera um nome descritivo para SEO: {slug}-palaz-strategy-company-{nome-original}
            // Se o nome original j├í come├ºar com o slug, n├úo repete
            let finalName = baseName;
            if (!baseName.includes(slug)) {
                finalName = `${slug}-palaz-strategy-company-${baseName}`;
            } else if (!baseName.includes('palaz-strategy-company')) {
                // Se tinha apenas 'palaz', substitui pelo nome completo
                if (baseName.includes(`${slug}-palaz-`)) {
                    finalName = baseName.replace(`${slug}-palaz-`, `${slug}-palaz-strategy-company-`);
                } else {
                    finalName = baseName.replace(slug, `${slug}-palaz-strategy-company`);
                }
            }

            const filename = `${finalName}${ext}`;
            const filePath = path.join(dirPath, filename);
            await fs.writeFile(filePath, new Uint8Array(buffer));
            urls.push(`/imagens/cases/${slug}/${filename}`);
        }

        return NextResponse.json({ success: true, urls });
    } catch (e: unknown) {
        const err = e as Error;
        console.error("Upload error:", err);
        return NextResponse.json({ error: err.message || "Something went wrong" }, { status: 500 });
    }
}

export async function DELETE(req: Request) {
    if (process.env.NODE_ENV !== "development") {
        return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    try {
        const { fileUrl } = await req.json();

        if (!fileUrl || !fileUrl.startsWith('/imagens/cases/')) {
            return NextResponse.json({ error: "Invalid URL" }, { status: 400 });
        }

        const absolutePath = path.join(process.cwd(), "public", fileUrl);

        try {
            await fs.unlink(absolutePath);
            return NextResponse.json({ success: true, message: "File deleted" });
        } catch (err: any) {
            if (err.code === 'ENOENT') {
                return NextResponse.json({ success: true, message: "File already deleted" });
            }
            throw err;
        }
    } catch (e: unknown) {
        return NextResponse.json({ error: "Failed to delete file" }, { status: 500 });
    }
}

