    const lastMousePos = useRef({ x: 0, y: 0 })

    // Motion Values para performance m├íxima
    const mouseX = useMotionValue(0)
    const mouseY = useMotionValue(0)

    // O cursor deve ser 100% preciso, seguindo o mouse sem delay ou efeito de mola
    const cursorX = mouseX
    const cursorY = mouseY

    const updateMousePosition = useCallback((e: MouseEvent) => {
        mouseX.set(e.clientX)
        mouseY.set(e.clientY)
        lastMousePos.current = { x: e.clientX, y: e.clientY }
    }, [mouseX, mouseY])

    const checkElementUnderMouse = useCallback((target: HTMLElement | null) => {
        if (!target) return
        const interactive = target.closest('a, button, [role="button"]')
        const project = target.closest(`[data-cursor-label="${verLabel}"]`)
        const label = target.closest('[data-cursor-label]')?.getAttribute('data-cursor-label')

        setIsHovering(!!interactive && !project)
        setCursorLabel(label || null)
    }, [verLabel])

    const [mounted, setMounted] = useState(false)

    useEffect(() => {
        setMounted(true)
        const handleMouseDown = () => setIsPressed(true)
        const handleMouseUp = () => setIsPressed(false)

        const onMouseMove = (e: MouseEvent) => {
            updateMousePosition(e)
            checkElementUnderMouse(e.target as HTMLElement)
        }

        const onMouseOver = (e: MouseEvent) => {
            checkElementUnderMouse(e.target as HTMLElement)
        }

        window.addEventListener("mousemove", onMouseMove)
        window.addEventListener("mousedown", handleMouseDown)
        window.addEventListener("mouseup", handleMouseUp)
        window.addEventListener("mouseover", onMouseOver)

        return () => {
            window.removeEventListener("mousemove", onMouseMove)
            window.removeEventListener("mousedown", handleMouseDown)
            window.removeEventListener("mouseup", handleMouseUp)
            window.removeEventListener("mouseover", onMouseOver)
        }
    }, [updateMousePosition, checkElementUnderMouse])

    if (!mounted) return null

    if (typeof window !== 'undefined' && window.matchMedia('(pointer: coarse)').matches) {
        return null
    }

    return (
        <div id="custom-cursor-container" className="fixed inset-0 pointer-events-none z-[9999] overflow-hidden hidden md:block" style={{ mixBlendMode: 'difference' }}>
            {/* Arpeggio Supreme Cursor - Ponto Laranja Vibrante #F24B0F */}
            <motion.div
                className="absolute top-0 left-0 flex items-center justify-center rounded-full pointer-events-none transition-colors duration-300"
                style={{
                    x: cursorX,
                    y: cursorY,
                    translateX: "-50%",
                    translateY: "-50%",
                    // Tamanho Arpeggio: 24px base -> 120px Glass Hover nos projetos
                    width: cursorLabel ? 120 : 24,
                    height: cursorLabel ? 120 : 24,
                    backgroundColor: cursorLabel ? "rgba(255, 255, 255, 0.6)" : "#F24B0F",
                    backdropFilter: cursorLabel ? "blur(8px)" : "none",
                }}
                animate={{
                    scale: isPressed ? 0.9 : 1,
                }}
                transition={{ type: "spring", stiffness: 500, damping: 40, mass: 0.2 }}
            >
                <AnimatePresence mode="wait">
                    {/* R├│tulo "VISIT" do Arpeggio (Minimalista e Elegante) */}
                    {cursorLabel === verLabel ? (
                        <motion.span
                            key="visit"
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            className="text-[14px] font-bold tracking-[0.1em] text-black uppercase font-sans"
                        >
                            {verLabel}
                        </motion.span>
                    ) : isHovering ? (
                        <motion.div
                            key="arrow"
                            initial={{ opacity: 0, scale: 0.5, rotate: -45 }}
                            animate={{ opacity: 1, scale: 1, rotate: 0 }}
                            exit={{ opacity: 0, scale: 0.5, rotate: 45 }}
                        >
                            <ArrowUpRight className="w-5 h-5 text-white" strokeWidth={2.5} />
                        </motion.div>
                    ) : cursorLabel && (
                        <motion.span
                            key="custom-label"
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.8 }}
                            className="text-[14px] font-bold tracking-[0.1em] text-black uppercase font-sans"
                        >
                            {cursorLabel}
                        </motion.span>
                    )}
                </AnimatePresence>
            </motion.div>
        </div>
    )
}

"use client";
import React, { memo, useEffect, useState } from "react";
import { X, ArrowUp, ArrowDown } from "lucide-react";
import { useDashboardStore } from "@/store/dashboardStore";

interface ReorderModalProps {
    isOpen: boolean;
    onClose: () => void;
}

const ReorderItem = memo(({ p, i, listLength, onMove }: { p: any, i: number, listLength: number, onMove: (idx: number, dir: 'up' | 'down') => void }) => {
    return (
        <div 
            className="flex items-center gap-4 bg-white/[0.04] p-3 rounded-xl border border-white/[0.06] hover:border-white/15 transition-all group"
        >
            <div className="flex flex-col gap-1 flex-shrink-0">
                <button 
                    onClick={() => onMove(i, 'up')}
                    disabled={i === 0}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-white/5 hover:bg-white/10 text-white/30 hover:text-white disabled:opacity-10 disabled:cursor-not-allowed transition-all"
                >
                    <ArrowUp size={14} />
                </button>
                <button 
                    onClick={() => onMove(i, 'down')}
                    disabled={i === listLength - 1}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-white/5 hover:bg-white/10 text-white/30 hover:text-white disabled:opacity-10 disabled:cursor-not-allowed transition-all"
                >
                    <ArrowDown size={14} />
                </button>
            </div>

            <div className="w-11 h-11 rounded-lg overflow-hidden bg-black/40 border border-white/5 flex-shrink-0 select-none pointer-events-none">
                {p.imageSrc && <img src={p.imageSrc} className="w-full h-full object-cover" alt="" loading="lazy" />}
            </div>

            <div className="flex-1 min-w-0 select-none lowercase">
                <div className="text-[15px] font-medium truncate">{p.title?.toLowerCase() || "sem t├¡tulo"}</div>
                <div className="text-[14px] text-white/20 mt-0.5">{p.category || "projeto"}</div>
            </div>

            <div className="text-white/10 text-[14px] font-mono select-none tabular-nums pr-2">
                {p.year}
            </div>
        </div>
    );
});

ReorderItem.displayName = "ReorderItem";

export function ReorderModal({ isOpen, onClose }: ReorderModalProps) {
    const { 
        projects, 
        setTempLists, 
        tempHomeList, 
        tempCasesList, 
        moveItem, 
        saveOrder, 
        isSaving 
    } = useDashboardStore();

    const [reorderTab, setReorderTab] = useState<'home' | 'cases'>('home');

    useEffect(() => {
        if (isOpen) {
            setTempLists(projects);
            setReorderTab('home');
        }
    }, [isOpen, projects, setTempLists]);

    if (!isOpen) return null;

    const handleSave = async () => {
        const success = await saveOrder(reorderTab);
        if (success) {
            onClose();
        }
    };

    const currentList = reorderTab === 'home' ? tempHomeList : tempCasesList;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => !isSaving && onClose()}></div>
            <div className="relative bg-[#111111] border border-white/10 rounded-3xl w-full max-w-2xl shadow-2xl flex flex-col max-h-[85vh] animate-in fade-in zoom-in-95 duration-200 overflow-hidden">
                <div className="p-8 border-b border-white/10 flex justify-between items-center bg-[#161616]">
                    <div>
                        <h2 className="text-[15px] font-medium text-white lowercase">reordenar cases</h2>
                        <p className="text-white/20 text-[14px] mt-1 lowercase">
                            {reorderTab === 'home' ? 'ordem de exibi├º├úo na home page.' : 'ordem de exibi├º├úo na p├ígina cases.'}
                        </p>
                    </div>
                    <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/5 hover:bg-white/10 flex items-center justify-center text-white/30 hover:text-white transition-all">
                        <X size={20} />
                    </button>
                </div>

                <div className="flex bg-[#111111] px-8 py-2">
                    {(['home', 'cases'] as const).map(tab => (
                        <button
                            key={tab}
                            onClick={() => setReorderTab(tab)}
                            className={`flex-1 py-4 text-[14px] transition-all relative lowercase ${
                                reorderTab === tab
                                    ? 'text-white font-medium'
                                    : 'text-white/20 hover:text-white/40'
                            }`}
                        >
                            {tab === 'home' ? 'home' : 'p├ígina cases'}
                            {reorderTab === tab && (
                                <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#F24B0F] shadow-[0_0_10px_rgba(242,75,15,0.5)]" />
                            )}
                        </button>
                    ))}
                </div>

                <div className="flex-1 overflow-y-auto p-8 custom-scrollbar bg-[#111111]">
                    <div className="flex flex-col gap-3">
                        {currentList.length === 0 ? (
                            <div className="py-20 text-center border border-dashed border-white/5 rounded-2xl">
                                <p className="text-[14px] font-medium text-white/10 lowercase">nenhum item nesta lista</p>
                            </div>
                        ) : (
                            currentList.map((p, i) => (
                                <ReorderItem 
                                    key={p.slug} 
                                    p={p} 
                                    i={i} 
                                    listLength={currentList.length} 
                                    onMove={(idx, dir) => moveItem(reorderTab, idx, dir)} 
                                />
                            ))
                        )}
                    </div>
                </div>

                <div className="p-8 border-t border-white/5 flex items-center justify-end gap-2 bg-[#161616]">
                    <button 
                        onClick={onClose} 
                        disabled={isSaving}
                        className="px-8 py-3 text-[14px] font-medium text-white/20 hover:text-white transition-colors disabled:opacity-50 lowercase"
                    >
                        cancelar
                    </button>
                    <button 
                        onClick={handleSave}
                        disabled={isSaving}
                        className="bg-[#F24B0F] text-white px-10 py-3 rounded-full text-[14px] font-medium hover:bg-[#ff5a1f] transition-all disabled:opacity-50 flex items-center gap-3 shadow-lg shadow-[#F24B0F]/10 hover:scale-105 active:scale-95 lowercase"
                    >
                        {isSaving ? "salvando..." : `salvar ordem (${reorderTab === 'home' ? 'home' : 'p├ígina'})`}
                    </button>
                </div>
            </div>
        </div>
    );
}

import { create } from 'zustand';

export interface Block {
    id: string;
    type: string;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    [key: string]: any;
    translations?: {
        pt?: Record<string, any>;
        en?: Record<string, any>;
    };
}

export interface EditorState {
    blocks: Block[];
    projectData: {
        id?: string;
        slug?: string;
        imageSrc?: string;
        year?: string;
        showOnHome?: boolean;
        role?: string;
        keywords?: string;
        lastUpdated?: string;
    };
    projectTranslations: {
        pt: Record<string, any>;
        en: Record<string, any>;
    };
    activeLang: 'pt' | 'en';
    isSaving: boolean;
    saveMessage: { type: 'success' | 'error', text: string } | null;
    dialog: { 
        open: boolean; 
        title: string; 
        message: string; 
        type: 'confirm' | 'alert'; 
        variant: 'danger' | 'warning' | 'info';
        onConfirm?: () => void;
    };

    // Actions
    resetEditor: () => void;
    setInitialData: (project: any) => void;
    setBlocks: (blocks: Block[]) => void;
    setActiveLang: (lang: 'pt' | 'en') => void;
    updateProjectData: (updates: Partial<EditorState['projectData']>) => void;
    updateProjectTranslation: (lang: 'pt' | 'en', field: string, value: any) => void;
    ensureSlug: () => string | null;
    updateBlock: (id: string, updates: Partial<Block> | ((prev: Block) => Block)) => void;
    addBlock: (type: string, template: Partial<Block>) => void;
    removeBlock: (id: string) => void;
    moveBlock: (id: string, direction: 'up' | 'down') => void;
    updateBlockTranslation: (id: string, lang: 'pt' | 'en', field: string, value: any) => void;
    deleteMedia: (path: string) => Promise<void>;
    setIsSaving: (isSaving: boolean) => void;
    setSaveMessage: (message: { type: 'success' | 'error', text: string } | null) => void;
    setDialog: (dialog: Partial<EditorState['dialog']>) => void;
}

export const slugify = (text: string) => {
    return text
        .toString()
        .normalize('NFD') // separa acentos das letras
        .replace(/[\u0300-\u036f]/g, '') // remove os acentos
        .toLowerCase()
        .trim()
        .replace(/\s+/g, '-') // substitui espa├ºos por -
        .replace(/[^\w-]+/g, '') // remove caracteres n├úo-word
        .replace(/--+/g, '-'); // remove hifens duplos
};

export const useEditorStore = create<EditorState>((set) => ({
    blocks: [],
    projectData: {
        showOnHome: false,
        year: new Date().getFullYear().toString(),
    },
    projectTranslations: {
        pt: {},
        en: {}
    },
    activeLang: 'pt',
    isSaving: false,
    saveMessage: null,
    dialog: {
        open: false,
        title: '',
        message: '',
        type: 'alert',
        variant: 'info'
    },

    resetEditor: () => set({
        blocks: [],
        projectData: {
            showOnHome: false,
            year: new Date().getFullYear().toString(),
        },
        projectTranslations: {
            pt: { title: '', description: '', client: '', category: '', role: '', keywords: '' },
            en: { title: '', description: '', client: '', category: '', role: '', keywords: '' }
        },
        activeLang: 'pt'
    }),

    setInitialData: (data) => {
        // A API retorna { projectData: {...}, translations: {...} }
        const project = data.projectData || data;
        const blocks = (project.blocks || project.contentBlocks || []).map((b: any) => ({
            id: b.id || Math.random().toString(36).substr(2, 9),
            ...b
        }));

        const defaultTrans = { title: '', description: '', client: '', category: '', role: '', keywords: '' };
        const ptTrans = { ...defaultTrans, ...(data.translations?.pt || {}) };
        const enTrans = { ...defaultTrans, ...(data.translations?.en || {}) };

        set({
            blocks,
            projectData: {
                id: project.id, // Keep existing ID
                slug: project.slug || '',
                imageSrc: project.imageSrc || '',
                year: project.year || new Date().getFullYear().toString(),
                showOnHome: !!project.showOnHome,
                role: project.role, // Keep existing role
                keywords: project.keywords, // Keep existing keywords
                lastUpdated: project.lastUpdated // Keep existing lastUpdated
            },
            projectTranslations: {
                pt: ptTrans,
                en: enTrans
            }
        });
    },

    setBlocks: (blocks) => set({ blocks }),

    setActiveLang: (activeLang) => set({ activeLang }),

    updateProjectData: (updates) => set((state) => ({
        projectData: { ...state.projectData, ...updates }
    })),

    updateProjectTranslation: (lang, field, value) => set((state) => {
        const newTranslations = {
            ...state.projectTranslations,
            [lang]: {
                ...state.projectTranslations[lang],
                [field]: value
            }
        };

        // Sincroniza com a raiz do projeto se for PT (comportamento herdado da V1)
        const projectUpdates: any = {};
        if (lang === 'pt') {
            projectUpdates[field] = value;
        }

        return {
            projectTranslations: newTranslations,
            projectData: { ...state.projectData, ...projectUpdates }
        };
    }),

    ensureSlug: () => {
        const state = useEditorStore.getState();
        if (state.projectData.slug) return state.projectData.slug;
        const title = state.projectTranslations.pt?.title || state.projectTranslations.en?.title || "";
        if (!title) return null;
        const generated = slugify(title);
        set((s) => ({ projectData: { ...s.projectData, slug: generated } }));
        return generated;
    },

    deleteMedia: async (fileUrl) => {
        try {
            await fetch("/api/editor/upload", {
                method: "DELETE",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ fileUrl }),
            });
        } catch (error) {
            console.error("Erro ao deletar m├¡dia:", error);
        }
    },

    setIsSaving: (isSaving) => set({ isSaving }),

    setSaveMessage: (saveMessage) => set({ saveMessage }),

    setDialog: (dialogUpdates) => set((state) => ({
        dialog: { ...state.dialog, ...dialogUpdates }
    })),

    updateBlock: (id, updates) => set((state) => ({
        blocks: state.blocks.map((block) => {
            if (block.id !== id) return block;
            if (typeof updates === 'function') return updates(block);
            return { ...block, ...updates };
        })
    })),

    addBlock: (type, template) => set((state) => ({
        blocks: [...state.blocks, { 
            id: Math.random().toString(36).substr(2, 9), 
            type, 
            ...JSON.parse(JSON.stringify(template))
        } as Block]
    })),

    removeBlock: (id) => set((state) => ({
        blocks: state.blocks.filter((block) => block.id !== id)
    })),

    moveBlock: (id, direction) => set((state) => {
        const index = state.blocks.findIndex(b => b.id === id);
        if (index === -1) return state;

        const newBlocks = [...state.blocks];
        if (direction === 'up' && index > 0) {
            [newBlocks[index], newBlocks[index - 1]] = [newBlocks[index - 1], newBlocks[index]];
        } else if (direction === 'down' && index < newBlocks.length - 1) {
            [newBlocks[index], newBlocks[index + 1]] = [newBlocks[index + 1], newBlocks[index]];
        }

        return { blocks: newBlocks };
    }),

    updateBlockTranslation: (id, lang, field, value) => set((state) => ({
        blocks: state.blocks.map((block) => {
            if (block.id !== id) return block;
            return {
                ...block,
                translations: {
                    ...(block.translations || {}),
                    [lang]: {
                        ...(block.translations?.[lang] || {}),
                        [field]: value
                    }
                },
                // Se for PT, atualiza tamb├®m a raiz para compatibilidade legada
                ...(lang === 'pt' ? { [field]: value } : {})
            };
        })
    })),
}));
